INSERT INTO church_history_facts (month, day, year, short_description, long_description) VALUES
(4, 21, 1109, 'Anselm of Canterbury dies, leaving a major theological legacy.', 'Anselm, Archbishop of Canterbury, died on 21 April 1109. He is remembered for shaping medieval theology through works on faith, reason, and atonement, and for defending the Church''s independence from royal control during the Investiture Controversy. His influence carried into later Anglican and Catholic thought, and his feast is kept on 21 April in many church calendars.'),
(4, 21, 1509, 'Henry VIII becomes king of England after Henry VII''s death.', 'Henry VII died on 21 April 1509, and Henry VIII immediately succeeded to the throne. Although still a loyal Catholic ruler at first, his reign later led to the break with Rome and the establishment of royal supremacy over the Church in England. This accession date marks the beginning of a reign that transformed English church history.'),
(4, 21, NULL, 'Many churches mark 21 April with remembrance of St Anselm.', 'In Anglican and Roman Catholic usage, 21 April is widely associated with St Anselm of Canterbury. Parish liturgies, educational materials, and sermons often use this day to reflect on theology, prayerful reasoning, and the relationship between Church and state in medieval and later English Christianity.');
